/**
 * Reproduction script for: v-bind's same-name shorthand fails (causes crash)
 * in in-DOM templates.
 *
 * In-DOM templates are parsed by the browser's HTML parser, which converts
 * :foo (no expression) to :foo="" (empty expression).
 * This script simulates that behavior and verifies the fix works.
 */
import {
  NodeTypes,
  createSimpleExpression,
  baseParse as parse,
  transform,
  type DirectiveNode,
  type ElementNode,
  type VNodeCall,
  type ObjectExpression,
} from './packages/compiler-core/src'
import { transformBind } from './packages/compiler-core/src/transforms/vBind'
import { transformElement } from './packages/compiler-core/src/transforms/transformElement'
import { transformVBindShorthand } from './packages/compiler-core/src/transforms/transformVBindShorthand'

function parseAndTransform(template: string) {
  const ast = parse(template)
  transform(ast, {
    nodeTransforms: [transformVBindShorthand, transformElement],
    directiveTransforms: {
      bind: transformBind,
    },
  })
  return ast.children[0] as ElementNode
}

// Test 1: Normal no-expression case (:id - no expression)
// This is the SFC/non-browser case
console.log('Test 1: :id (no expression) - standard shorthand')
const node1 = parseAndTransform('<div :id />')
const props1 = (node1.codegenNode as VNodeCall).props as ObjectExpression
const prop1 = props1.properties[0]
console.assert(
  prop1.key.type === NodeTypes.SIMPLE_EXPRESSION &&
    (prop1.key as any).content === 'id',
  'key should be "id"',
)
console.assert(
  prop1.value.type === NodeTypes.SIMPLE_EXPRESSION &&
    (prop1.value as any).content === 'id' &&
    !(prop1.value as any).isStatic,
  'value should be dynamic "id"',
)
console.log('  ✓ Passed\n')

// Test 2: Simulate browser-parsed `:param=""` (in-DOM template)
// In the browser, `:param` is parsed as `:param=""` by the HTML parser
// This was the failing case before the fix
console.log('Test 2: :param="" (simulated browser/in-DOM template parsing)')
const ast2 = parse('<div :param />')
// Simulate browser behavior: the HTML parser sets exp to empty string
const element2 = ast2.children[0] as ElementNode
const directive2 = element2.props[0] as DirectiveNode
// Manually set exp to empty string (simulating browser HTML parser behavior)
directive2.exp = createSimpleExpression('', false, directive2.loc)

transform(ast2, {
  nodeTransforms: [transformVBindShorthand, transformElement],
  directiveTransforms: {
    bind: transformBind,
  },
})

const node2 = ast2.children[0] as ElementNode
const props2 = (node2.codegenNode as VNodeCall).props as ObjectExpression
const prop2 = props2.properties[0]
console.assert(
  prop2.key.type === NodeTypes.SIMPLE_EXPRESSION &&
    (prop2.key as any).content === 'param',
  `key should be "param", got "${(prop2.key as any).content}"`,
)
console.assert(
  prop2.value.type === NodeTypes.SIMPLE_EXPRESSION &&
    (prop2.value as any).content === 'param' &&
    !(prop2.value as any).isStatic,
  `value should be dynamic "param", got "${(prop2.value as any).content}"`,
)
console.log('  ✓ Passed\n')

// Test 3: camelized attribute in browser case
console.log('Test 3: :foo-bar="" (camelized, simulated browser)')
const ast3 = parse('<div :foo-bar />')
const element3 = ast3.children[0] as ElementNode
const directive3 = element3.props[0] as DirectiveNode
directive3.exp = createSimpleExpression('', false, directive3.loc)

transform(ast3, {
  nodeTransforms: [transformVBindShorthand, transformElement],
  directiveTransforms: {
    bind: transformBind,
  },
})

const node3 = ast3.children[0] as ElementNode
const props3 = (node3.codegenNode as VNodeCall).props as ObjectExpression
const prop3 = props3.properties[0]
// key should still be original, value should be camelized
console.assert(
  prop3.value.type === NodeTypes.SIMPLE_EXPRESSION &&
    (prop3.value as any).content === 'fooBar' &&
    !(prop3.value as any).isStatic,
  `value should be dynamic "fooBar" (camelized), got "${(prop3.value as any).content}"`,
)
console.log('  ✓ Passed\n')

// Test 4: Normal bind with explicit expression still works
console.log('Test 4: :id="myId" (explicit expression, should still work)')
const node4 = parseAndTransform('<div :id="myId" />')
const props4 = (node4.codegenNode as VNodeCall).props as ObjectExpression
const prop4 = props4.properties[0]
console.assert(
  prop4.value.type === NodeTypes.SIMPLE_EXPRESSION &&
    (prop4.value as any).content === 'myId' &&
    !(prop4.value as any).isStatic,
  `value should be dynamic "myId", got "${(prop4.value as any).content}"`,
)
console.log('  ✓ Passed\n')

// Test 5: Multiple bindings, some shorthand (browser case)
console.log('Test 5: Multiple props with shorthand in browser case')
const ast5 = parse('<div :id :class="someClass" :param />')
const element5 = ast5.children[0] as ElementNode
// Set :id and :param to empty string (browser parsing)
;(element5.props[0] as DirectiveNode).exp = createSimpleExpression(
  '',
  false,
  element5.props[0].loc,
)
;(element5.props[2] as DirectiveNode).exp = createSimpleExpression(
  '',
  false,
  element5.props[2].loc,
)

transform(ast5, {
  nodeTransforms: [transformVBindShorthand, transformElement],
  directiveTransforms: {
    bind: transformBind,
  },
})

const node5 = ast5.children[0] as ElementNode
const props5 = (node5.codegenNode as VNodeCall).props as ObjectExpression
// Should have 3 properties
console.assert(
  props5.properties.length === 3,
  `should have 3 properties, got ${props5.properties.length}`,
)
// :id shorthand
console.assert(
  (props5.properties[0].value as any).content === 'id' &&
    !(props5.properties[0].value as any).isStatic,
  ':id shorthand value should be dynamic "id"',
)
// :class="someClass" explicit
console.assert(
  (props5.properties[1].value as any).content === 'someClass' &&
    !(props5.properties[1].value as any).isStatic,
  ':class value should be dynamic "someClass"',
)
// :param shorthand
console.assert(
  (props5.properties[2].value as any).content === 'param' &&
    !(props5.properties[2].value as any).isStatic,
  ':param shorthand value should be dynamic "param"',
)
console.log('  ✓ Passed\n')

console.log('All tests passed! The fix works correctly.')

